#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef long long LL;typedef unsigned short uS;
unsigned short cnt[1<<26];
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int Get(){char ch;do ch=getchar();while(ch<'a'||ch>'z');return ch-'a';}
const int N=60010;struct Nd{uS l,r,idx;}q[N];int n,Q,L,R,s[N];unsigned ans[N],Ans;
inline void ins(const int &x){Ans+=(cnt[x]++);for(int i=0;i<26;++i)Ans+=cnt[x^(1<<i)];}
inline void del(const int &x){Ans-=(--cnt[x]);for(int i=0;i<26;++i)Ans-=cnt[x^(1<<i)];}
int main()
{
	n=read()+1;Q=read();rep(2,n,i)s[i]=s[i-1]^(1<<Get());rep(1,Q,i)q[i].l=read(),q[i].r=read()+1,q[i].idx=i;
	std::sort(q+1,q+Q+1,[&](const Nd&x,const Nd&y){return (x.l>>8)==(y.l>>8)?((x.l>>8)&1?x.r>y.r:x.r<y.r):x.l<y.l;});
	L=q[1].l;R=q[1].l-1;rep(1,Q,i)
	{
		while(R<q[i].r)ins(s[++R]);while(L>q[i].l)ins(s[--L]);
		while(R>q[i].r)del(s[R--]);while(L<q[i].l)del(s[L++]);
		ans[q[i].idx]=Ans;
	}
	rep(1,Q,i)printf("%u\n",ans[i]);return 0;
}
